#[no_mangle]
/// handle an interrupt, exception, or system call from user space
pub fn trap_handler() {
    //记录用户空间花费CPU时间，同时准备内核空间花费CPU时间
    current_task()
        .unwrap()
        .inner_lock()
        .time_data
        .update_utime();

    let hartid = hart_id();

    set_kernel_trap_entry();
    let scause = scause::read();
    let stval = stval::read();
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            let syscall_id = Syscall::from(cx.gp.x[17]);
            // get system call return value
            let result = syscall(
                cx.gp.x[17],
                [
                    cx.gp.x[10],
                    cx.gp.x[11],
                    cx.gp.x[12],
                    cx.gp.x[13],
                    cx.gp.x[14],
                    cx.gp.x[15],
                ],
            );
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.gp.x[10] = match result {
                Ok(res) => res,
                Err(errno) => -(errno as isize) as usize,
            };
            // handle error
            match result {
                Ok(ret) => debug!("[syscall ret] {:?} ret = {}", syscall_id, ret),
                Err(errno) => debug!("[syscall ret] {:?} ret = {}", syscall_id, errno.str()),
            }
        }
        Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::LoadPageFault)
        | Trap::Exception(Exception::InstructionPageFault) => {
            //debug!("{:?},bad addr = {:#x}", scause.cause(), stval);
            // page fault
            let mut ok;
            {
                let task = current_task().unwrap();
                let task_inner = task.inner_lock();
                ok = task_inner
                    .memory_set
                    .lazy_page_fault(VirtAddr::from(stval).floor(), scause.cause());
                if !ok {
                    ok = task_inner
                        .memory_set
                        .cow_page_fault(VirtAddr::from(stval).floor(), scause.cause());
                }
                // drop task inner and task to avoid deadlock and exit exception
            }
            if !ok {
                warn!(
                    "[kernel] hart {} {:?} in application, bad addr = {:#x}, bad instruction = {:#x}, kernel killed it.",
                    hartid,
                    scause.cause(),
                    stval,
                    current_trap_cx().sepc,
                );
                //发送段错误信号
                warn!("send SIGSEGV signal!");
                let tid = current_task().unwrap().tid();
                send_signal_to_thread(tid, SigSet::SIGSEGV);
                // page fault exit code
                //exit_current_and_run_next(-2);
            }
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::LoadFault) => {
            warn!(
                "[kernel] hart {} {:?} in application, bad addr = {:#x}, bad instruction = {:#x}, kernel killed it.",
                hartid,
                scause.cause(),
                stval,
                current_trap_cx().sepc,
            );
            // page fault exit code
            exit_current_and_run_next(-2);
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            backtrace();
            warn!(
                "[kernel] [hart {}] IllegalInstruction at {:#x} in application, kernel killed it.",
                hartid,
                current_trap_cx().sepc,
            );
            // illegal instruction exit code
            exit_current_and_run_next(-3);
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            // 检查futex操作是否超时
            check_futex_timer();
            // debug!("Timer Interupt!");
            suspend_current_and_run_next();
            // set_next_trigger();
        }
        Trap::Exception(Exception::Breakpoint) => {
            warn!(
                "[kernel] Breakpoint from application, sepc = {:#x}",
                sepc::read(),
            );
            // jump to next instruction anyway
            let cx = current_trap_cx();
            cx.sepc += 2;
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }
    //flush_tlb();
    //检查定时器
    current_task().unwrap().check_timer();

    //记录内核空间花费CPU时间，同时准备用户空间花费CPU时间
    current_task()
        .unwrap()
        .inner_lock()
        .time_data
        .update_stime();
}

#[no_mangle]
pub fn trap_return() {
    //检查信号
    if let Some(signo) = check_if_any_sig_for_current_task() {
        debug!("found signo in trap_return");
        handle_signal(signo);
    }
    if scause::read().cause() == Trap::Interrupt(Interrupt::SupervisorTimer) {
        set_next_trigger();
    }

    if scause::read().cause() == Trap::Interrupt(scause::Interrupt::SupervisorTimer) {
        set_next_trigger();
    }

    set_user_trap_entry();
    extern "C" {
        #[allow(improper_ctypes)]
        fn __return_to_user(cx: *mut TrapContext);
    }
    unsafe {
        // 方便调试进入__return_to_user
        let trap_cx = current_trap_cx();
        __return_to_user(trap_cx);
    }
}

#[no_mangle]
pub fn trap_loop() {
    loop {
        trap_return();
        trap_handler();
    }
}

#[no_mangle]
pub fn trap_from_kernel() -> ! {
    backtrace();
    let stval = stval::read();
    let sepc = sepc::read();
    let stval_vpn = VirtPageNum::from(VirtAddr::from(stval));
    let sepc_vpn = VirtPageNum::from(VirtAddr::from(sepc));
    panic!(
        "stval = {:#x}(vpn {}), sepc = {:#x}(vpn{}),
        a trap {:?} from kernel!",
        stval,
        stval_vpn.0,
        sepc,
        sepc_vpn.0,
        scause::read().cause()
    );
}

//! Implementation of [`TrapContext`]
use riscv::register::sstatus::{self, Sstatus, SPP};

use crate::signal::{SigSet, SignalStack};

use super::trap_loop;

#[repr(C)]
#[derive(Debug, Default, Clone, Copy)]
pub struct GeneralRegs {
    pub x: [usize; 32],
}

/// FP registers
#[repr(C)]
#[derive(Debug, Default, Clone, Copy)]
pub struct FloatRegs {
    pub f: [usize; 32],
    pub fcsr: u32,
}

#[repr(C)]
#[derive(Default, Debug, Clone, Copy)]
pub struct MachineContext {
    gp: GeneralRegs,
    fp: FloatRegs,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct UserContext {
    pub flags: usize,
    pub link: usize,
    pub stack: SignalStack,
    pub sigmask: SigSet,
    pub __pad: [u8; 128],
    pub mcontext: MachineContext,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
///trap context structure containing sstatus, sepc and registers
pub struct TrapContext {
    /// user trap to kernel need to save those regs
    /// general regs[0..31]
    pub gp: GeneralRegs,
    /// CSR sstatus      
    pub sstatus: Sstatus, // 32
    /// CSR sepc
    pub sepc: usize, // 33
    /// kernel return to user need to save those regs
    pub kernel_sp: usize, // 34
    pub kernel_ra: usize,      // 35 trap_loop
    pub kernel_s: [usize; 12], // 36 - 47
    pub kernel_fp: usize,      // 48
    /// kernel hart address
    pub kernel_tp: usize, // 49
    /// A copy of register a0, useful when we need to restart syscall
    pub origin_a0: usize, // 50
    /// float regs 51-82, fcsr 83
    pub fp: FloatRegs,
}

impl TrapContext {
    ///set stack pointer to x_2 reg (sp)
    pub fn set_sp(&mut self, sp: usize) {
        self.gp.x[2] = sp;
    }
    ///init app context
    pub fn app_init_context(entry: usize, sp: usize, kernel_sp: usize) -> Self {
        let mut sstatus = sstatus::read();
        sstatus.set_spp(SPP::User);
        let mut cx = Self {
            gp: GeneralRegs { x: [0; 32] },
            sstatus,
            sepc: entry,
            kernel_sp,
            kernel_ra: trap_loop as usize,
            kernel_s: [0; 12],
            kernel_fp: 0,
            kernel_tp: 0,
            origin_a0: 0,
            fp: FloatRegs {
                f: [0; 32],
                fcsr: 0,
            },
        };
        cx.set_sp(sp);
        cx
    }
    pub fn as_mctx(&self) -> MachineContext {
        let mut x = [0; 32];
        x.copy_from_slice(&self.gp.x);
        let mut f = [0; 32];
        f.copy_from_slice(&self.fp.f);
        let fcsr = self.fp.fcsr;
        x[0] = self.sepc; // x0 寄存器永远为0,暂时借用一下,用于保存sepc
        MachineContext {
            gp: GeneralRegs { x },
            fp: FloatRegs { f, fcsr },
        }
    }
    pub fn copy_from_mctx(&mut self, mctx: MachineContext) {
        self.gp = mctx.gp;
        self.fp = mctx.fp;
        self.sepc = self.gp.x[0];
        self.gp.x[0] = 0;
    }
}

