use crate::{
    mm::PhysAddr,
    utils::{SysErrNo, SyscallRet},
};

use super::{block_current_and_run_next, current_task, wakeup_futex_task, TaskControlBlock};
use alloc::{
    collections::{BTreeMap, VecDeque},
    sync::{Arc, Weak},
};
use spin::{Lazy, Mutex};

type WaitQueue = VecDeque<Weak<TaskControlBlock>>;

/// 如果是PRIVATE_FUTEX,pid为进程的pid,否则pid为0(用户进程pid从1开始,0未被使用)
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
pub struct FutexKey {
    pa: PhysAddr,
    pid: usize,
}

impl FutexKey {
    pub fn new(pa: PhysAddr, pid: usize) -> Self {
        Self { pa, pid }
    }
}

pub static FUTEX_QUEUE: Lazy<Mutex<BTreeMap<FutexKey, WaitQueue>>> =
    Lazy::new(|| Mutex::new(BTreeMap::new()));

pub fn futex_wait(key: FutexKey) -> SyscallRet {
    let mut waitq = FUTEX_QUEUE.lock();
    let task = current_task().unwrap();
    if let Some(queue) = waitq.get_mut(&key) {
        queue.push_back(Arc::downgrade(&task));
    } else {
        waitq.insert(key, {
            let mut queue = VecDeque::new();
            queue.push_back(Arc::downgrade(&task));
            queue
        });
    }
    log::debug!("[futex_wait] blocked!");
    drop(task);
    drop(waitq);
    block_current_and_run_next();
    let task = current_task().unwrap();
    let task_inner = task.inner_lock();
    // woke by signal
    if !task_inner
        .sig_pending
        .difference(task_inner.sig_mask)
        .is_empty()
    {
        return Err(SysErrNo::EINTR);
    }
    Ok(0)
}

pub fn futex_wake_up(key: FutexKey, max_num: i32) -> usize {
    log::debug!(
        "[sys_futex] futex wakeup thread,max_num={},key={:?}",
        max_num,
        key
    );
    let mut futex_queue = FUTEX_QUEUE.lock();
    let mut num = 0;
    if let Some(queue) = futex_queue.get_mut(&key) {
        loop {
            if num >= max_num as usize {
                break;
            }
            if let Some(weak_task) = queue.pop_front() {
                if let Some(task) = weak_task.upgrade() {
                    //debug!("wake up task {}", task.pid());
                    wakeup_futex_task(task);
                    num += 1;
                }
            } else {
                break;
            }
        }
    }
    num
}

pub fn futex_requeue(old_key: FutexKey, max_num: i32, new_key: FutexKey, max_num2: i32) -> usize {
    log::debug!(
        "[futex_requeue],old_key={:?},max_num={},new_key={:?},max_num2={}",
        old_key,
        max_num,
        new_key,
        max_num2
    );
    let mut futex_queue = FUTEX_QUEUE.lock();
    let mut num = 0;
    let mut num2 = 0;
    let mut tmp = VecDeque::new();
    if let Some(queue) = futex_queue.get_mut(&old_key) {
        while let Some(weak_task) = queue.pop_front() {
            if let Some(task) = weak_task.upgrade() {
                if num < max_num {
                    wakeup_futex_task(task);
                    num += 1;
                } else if num2 < max_num2 {
                    tmp.push_back(Arc::downgrade(&task));
                    num2 += 1;
                }
            }
        }
    }
    if !tmp.is_empty() {
        futex_queue
            .entry(new_key)
            .or_insert_with(VecDeque::new)
            .extend(tmp);
    }
    num as usize
}

//!Implementation of [`PidAllocator`]
use crate::{
    config::mm::{KERNEL_STACK_SIZE, KSTACK_TOP, PAGE_SIZE},
    mm::{MapAreaType, MapPermission, VirtAddr, KERNEL_SPACE},
};
use alloc::vec::Vec;
use spin::{Lazy, Mutex};
///Pid Allocator struct
pub struct TidAllocator {
    current: usize,
    recycled: Vec<usize>,
}

impl TidAllocator {
    ///Create an empty `TidAllocator`
    pub fn new() -> Self {
        TidAllocator {
            current: 1,
            recycled: Vec::new(),
        }
    }
    ///Allocate a tid
    pub fn alloc(&mut self) -> TidHandle {
        if let Some(tid) = self.recycled.pop() {
            TidHandle(tid)
        } else {
            self.current += 1;
            TidHandle(self.current - 1)
        }
    }
    ///Recycle a tid
    pub fn dealloc(&mut self, tid: usize) {
        assert!(tid < self.current);
        assert!(
            !self.recycled.iter().any(|ttid| *ttid == tid),
            "pid {} has been deallocated!",
            tid
        );
        self.recycled.push(tid);
    }
}

pub static TID_ALLOCATOR: Lazy<Mutex<TidAllocator>> = Lazy::new(|| Mutex::new(TidAllocator::new()));

///Bind pid lifetime to `TidHandle`
pub struct TidHandle(pub usize);

impl Drop for TidHandle {
    fn drop(&mut self) {
        TID_ALLOCATOR.lock().dealloc(self.0);
    }
}
///Allocate a pid from PID_ALLOCATOR
pub fn tid_alloc() -> TidHandle {
    TID_ALLOCATOR.lock().alloc()
}

/// Return (bottom, top) of a kernel stack in kernel space.
pub fn kernel_stack_position(app_id: usize) -> (usize, usize) {
    let top = KSTACK_TOP - app_id * (KERNEL_STACK_SIZE + PAGE_SIZE);
    let bottom = top - KERNEL_STACK_SIZE;
    (bottom, top)
}
///Kernelstack for app
pub struct KernelStack {
    tid: usize,
}

impl KernelStack {
    ///Create a kernelstack from pid
    pub fn new(tid_handle: &TidHandle) -> Self {
        let (kernel_stack_bottom, kernel_stack_top) = kernel_stack_position(tid_handle.0);
        KERNEL_SPACE.lock().insert_framed_area(
            kernel_stack_bottom.into(),
            kernel_stack_top.into(),
            MapPermission::R | MapPermission::W,
            MapAreaType::Stack,
        );
        KernelStack { tid: tid_handle.0 }
    }
    ///Get the value on the top of kernelstack
    pub fn top(&self) -> usize {
        let (_, kernel_stack_top) = kernel_stack_position(self.tid);
        kernel_stack_top
    }
    /// Return (bottom, top) of a kernel stack in kernel space.)
    pub fn pos(&self) -> (usize, usize) {
        kernel_stack_position(self.tid)
    }
    pub fn bottom(&self) -> usize {
        let (kernel_stack_bottom, _) = kernel_stack_position(self.tid);
        kernel_stack_bottom
    }
}

impl Drop for KernelStack {
    fn drop(&mut self) {
        KERNEL_SPACE
            .lock()
            .remove_area_with_start_vpn(VirtAddr::from(self.bottom()).floor());
    }
}

