**实现**：`os/src/task/switch.S`

```asm
__switch:
    # 保存当前任务的上下文
    sd sp, 8(a0)      # 保存栈指针
    sd ra, 0(a0)      # 保存返回地址
    .set n, 0
    .rept 12
        SAVE_SN %n    # 保存 s0-s11
        .set n, n + 1
    .endr

    # 恢复下一个任务的上下文
    ld ra, 0(a1)      # 恢复返回地址
    .set n, 0
    .rept 12
        LOAD_SN %n    # 恢复 s0-s11
        .set n, n + 1
    .endr
    ld sp, 8(a1)      # 恢复栈指针
    ret
```

