pub fn normalize_path(path: &str) -> String {
    let mut components = Vec::new();
    for component in path.split('/') {
        match component {
            "" | "." => {}
            ".." => { components.pop(); }
            _ => { components.push(component); }
        }
    }
    format!("/{}", components.join("/"))
}

